mapper.select:
SELECT /* RcpMgmtMapper.rcpMgmtList */ DECODE(REQ.SERVICE_TYPE, 'PO', '후불', '선불') AS SERVICE_NAME /* 구분 */ ,REQ.RES_NO AS RES_NO /* 예약번호 */ ,CST.CSTMR_NAME AS CSTMR_NAME /* 고객명 */ ,TRIM(CST.CSTMR_FOREIGNER_RRN) AS CSTMR_FOREIGNER_RRN /* 주민번호 */ ,TRIM(CST.CSTMR_NATIVE_RRN) AS CSTMR_NATIVE_RRN /* 주민번호 */ ,DECODE(REQ.CSTMR_TYPE, 'FN', TRIM(CST.CSTMR_FOREIGNER_RRN), TRIM(CST.CSTMR_NATIVE_RRN)) AS SSN /* 주민번호 */ ,TRIM(CST.CSTMR_MOBILE_FN) || '-' || TRIM(CST.CSTMR_MOBILE_MN) || '-' || TRIM(CST.CSTMR_MOBILE_RN) AS CSTMR_MOBILE /* 핸드폰번호 */ ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = REQ.CNTPNT_SHOP_ID) || '/' || REQ.CNTPNT_SHOP_ID AS AGENT_NAME /* 대리점 */ ,(SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = SAL.SOC_CODE AND SERVICE_TYPE = 'P' AND ROWNUM = 1) || '(' || SAL.SOC_CODE || ')' AS SOC_NAME /* 요금제 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP9001' AND CD_VAL = REQ.OPER_TYPE) AS OPER_NAME /* 업무구분 */ ,TO_CHAR(REQ.REQ_IN_DAY, 'YYYY-MM-DD') AS REQ_IN_DAY /* 신청일자 */ ,DECODE(REQ.REQUEST_STATE_CODE, '00','접수대기', '01','접수', '08','배송대기(소화물)', '09','배송대기(택배)', '10','배송중', '20','개통대기', '21','개통완료' ) AS REQUEST_STATE_NAME /* 진행상태*/ ,DECODE(REQ.PSTATE,'00','정상','10','고객취소','20','관리자삭제') AS PSTATE_NAME /* 신청서상태 */ ,DECODE(REQ.ON_OFF_TYPE, '1', '오프라인', '2', '홈쇼핑', '온라인') AS ON_OFF_NAME /* 온/오프라인 */ ,REQ.ON_OFF_TYPE AS ON_OFF_TYPE ,REQ.OPEN_MARKET_REFERER AS OPEN_MARKET_REFERER /* 유입경로 */ ,DECODE(REQ.REC_YN, 'Y', 'Y', 'N') AS REC_YN /* 녹취여부 */ ,NVL(REQ.SHOP_NM, (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = REQ.SHOP_CD) || '/' || REQ.SHOP_CD) AS SHOP_NM /* 판매점 */ ,(SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = REQ.SHOP_USM_ID) || '/' || REQ.SHOP_USM_ID AS USR_NM /* 판매자 */ ,REQ.REQUEST_KEY FROM MCP_REQUEST@DL_MCP REQ, MCP_REQUEST_CSTMR@DL_MCP CST, MCP_REQUEST_SALEINFO@DL_MCP SAL WHERE REQ.REQUEST_KEY = CST.REQUEST_KEY AND CST.REQUEST_KEY = SAL.REQUEST_KEY AND REQ.SERVICE_TYPE = 'PP' /* 선불 데이터만 조회 */
AND REQ.REQ_IN_DAY BETWEEN TO_DATE(#{searchStartDt},'YYYYMMDD') AND TO_DATE(#{searchEndDt},'YYYYMMDD') + 1 /*신청일자*/
AND REQ.OPER_TYPE = #{pOperType} /*신청유형-신규가입/번호이동정보/기기변경정보*/
AND REQ.CNTPNT_SHOP_ID = #{cntpntShopId}
AND REQ.SHOP_CD = #{pAgentCode}
AND (REQ.SHOP_CD = #{pAgentCode} OR REQ.CNTPNT_SHOP_ID = #{pAgentCode})
AND REQ.SHOP_CD = #{pAgentCode}
AND REQ.REQUEST_STATE_CODE = #{pRequestStateCode} /*접수상태코드-진행상태*/
AND CST.CSTMR_NAME LIKE '%' || #{pSearchName} || '%' /*검색구분-고객명(pSearchGbn=1로 구분)*/
AND REQ.CONTRACT_NUM = #{pSearchName} /*검색구분-예약번호(pSearchGbn=2로 구분)*/
AND CST.CSTMR_MOBILE_FN || CST.CSTMR_MOBILE_MN || CST.CSTMR_MOBILE_RN LIKE '%'|| TRANSLATE(#{pSearchName},'1234567890-','1234567890')||'%' /*검색구분-휴대폰번호(searchGbn=3로 구분)*/
AND REQ.RES_NO = #{pSearchName}
AND REQ.PSTATE = #{pPstate}
AND REQ.REQ_BUY_TYPE = #{reqBuyType}
ORDER BY REQ.REQUEST_KEY DESC

SELECT /* RcpMgmtMapper.rcpMgmtList */ NVL(DECODE(REQ.SERVICE_TYPE, 'PO', '후불', '선불'), '-') AS SERVICE_NAME, /* 구분 */ NVL(REQ.RES_NO, '-') AS RES_NO, /* 예약번호 */ NVL(CST.CSTMR_NAME, '-') AS CSTMR_NAME, /* 고객명 */ NVL(DECODE(REQ.CSTMR_TYPE, 'FN', TRIM(CST.CSTMR_FOREIGNER_RRN), TRIM(CST.CSTMR_NATIVE_RRN)), '-') AS SSN, /* 주민번호 */ NVL(DECODE(REQ.REQ_BUY_TYPE, 'MM', '단말구매', 'UU', '유심단독구매', '-'), '-') AS REQ_BUY_TYPE, /* 구매유형 */ NVL((SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP9005' AND CD_VAL = MOV.MOVE_COMPANY), '-') AS MOVE_COMPANY , /* 이동전 통신사 */ NVL((SELECT PRDT_NM || '(' || PRDT_CODE || ')' FROM CMN_INTM_MDL WHERE PRDT_ID = SAL.MODEL_ID), '-') AS PRDT_NM, /* 제품명 */ NVL((SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'CMN0044' AND X.USG_YN = 'Y' AND X.CD_VAL = REQ.REQ_MODEL_COLOR), '-') AS PRDT_COLR_NM, /* 제품색생 */ NVL(TRIM(CST.CSTMR_MOBILE_FN) || '-' || TRIM(CST.CSTMR_MOBILE_MN) || '-' || TRIM(CST.CSTMR_MOBILE_RN), '-') AS CSTMR_MOBILE, /* 핸드폰번호 */ NVL((SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = REQ.CNTPNT_SHOP_ID) || '/' || REQ.CNTPNT_SHOP_ID, '-') AS AGENT_NAME, /* 대리점 */ NVL((SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = SAL.SOC_CODE AND SERVICE_TYPE = 'P' AND ROWNUM = 1) || '(' || SAL.SOC_CODE || ')' , '-') AS SOC_NAME, /* 요금제 */ NVL((SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP9001' AND CD_VAL = REQ.OPER_TYPE), '-') AS OPER_NAME , /* 업무구분 */ NVL(CST.CSTMR_ADDR || ' ' || CST.CSTMR_ADDR_DTL, '-') AS CSTMR_ADDR, /* 고객주소 */ NVL(DLV.DLVRY_ADDR || ' ' || DLV.DLVRY_ADDR_DTL, '-') AS DLVRY_ADDR, /* 배송주소 */ NVL(SUBSTR(DLV.DLVRY_POST,1,3) || '-' || SUBSTR(DLV.DLVRY_POST,4,3), '-') AS DLVRY_POST, /* 배송우편번호 */ NVL(TRIM(DLV.DLVRY_MOBILE_FN) || '-' || TRIM(DLV.DLVRY_MOBILE_MN) || '-' || TRIM(DLV.DLVRY_MOBILE_RN), '-') AS DLVRY_MOBILE , /* 배송지 휴대폰 */ NVL(TRIM(CST.CSTMR_TEL_FN) || '-' || TRIM(CST.CSTMR_TEL_MN) || '-' || TRIM(CST.CSTMR_TEL_RN), '-') AS CSTMR_TEL_NO, /* 고객 유선 */ NVL(TO_CHAR(REQ.REQ_IN_DAY, 'YYYY-MM-DD'), '-') AS REQ_IN_DAY, /* 신청일자 */ NVL(DECODE(REQ.REQUEST_STATE_CODE,'00','접수대기','01','접수','08','배송대기(소화물)','09','배송대기(택배)','10','배송중','20','개통대기','21','개통완료'), '-') AS REQUEST_STATE_NAME, /* 진행상태 */ NVL(DECODE(REQ.PSTATE,'00','정상','10','고객취소','20','관리자삭제'), '-') AS PSTATE_NAME, /* 신청서상태 */ NVL(DECODE(REQ.ON_OFF_TYPE, '1', '오프라인', '2', '홈쇼핑', '온라인'), '-') AS ON_OFF_NAME, /* 온/오프라인 */ NVL(REQ.ON_OFF_TYPE, '-') AS ON_OFF_TYPE, /* 온/오프라인 */ NVL(REQ.OPEN_MARKET_REFERER, '-') AS OPEN_MARKET_REFERER, /* 유입경로 */ NVL(DECODE(REQ.REC_YN, 'Y', 'Y', 'N'), '-') AS REC_YN /* 녹취여부 */ FROM MCP_REQUEST@DL_MCP REQ, MCP_REQUEST_CSTMR@DL_MCP CST, MCP_REQUEST_SALEINFO@DL_MCP SAL, MCP_REQUEST_MOVE@DL_MCP MOV, MCP_REQUEST_DLVRY@DL_MCP DLV WHERE REQ.REQUEST_KEY = CST.REQUEST_KEY AND CST.REQUEST_KEY = SAL.REQUEST_KEY AND SAL.REQUEST_KEY = MOV.REQUEST_KEY AND MOV.REQUEST_KEY = DLV.REQUEST_KEY
AND REQ.REQ_IN_DAY BETWEEN TO_DATE(#{searchStartDt},'YYYY-MM-DD') AND TO_DATE(#{searchEndDt},'YYYY-MM-DD') + 1 /*신청일자*/
AND REQ.SERVICE_TYPE = 'PP' /*서비스타입-선후불*/
AND REQ.CNTPNT_SHOP_ID = #{cntpntShopId}
AND REQ.SHOP_CD = #{pAgentCode}
AND (REQ.SHOP_CD = #{pAgentCode} OR REQ.CNTPNT_SHOP_ID = #{pAgentCode})
AND REQ.SHOP_CD = #{pAgentCode}
AND REQ.REQUEST_STATE_CODE = #{pRequestStateCode} /*접수상태코드-진행상태*/
AND CST.CSTMR_NAME like '%'||#{pSearchName}||'%' /*검색구분-고객명(pSearchGbn=1로 구분)*/
AND REQ.CONTRACT_NUM = #{pSearchName} /*검색구분-예약번호(pSearchGbn=2로 구분)*/
AND CST.CSTMR_MOBILE_FN || CST.CSTMR_MOBILE_MN || CST.CSTMR_MOBILE_RN LIKE '%'|| TRANSLATE(#{pSearchName},'1234567890-','1234567890')||'%' /*검색구분-휴대폰번호(searchGbn=3로 구분)*/
AND REQ.RES_NO = #{pSearchName}
AND REQ.PSTATE =#{pPstate}
AND REQ.REQ_BUY_TYPE =#{reqBuyType}
ORDER BY REQ.REQUEST_KEY DESC
